        const loadFilter = useCallback(() => {
        if (isInitialized) return; // Evita múltiplas chamadas    

         const filtro = {} as FilterCargos; 
  
              const filtroMem = sessionStorage.getItem(btoa('CargosFilter')) ? JSON.parse(atob(sessionStorage.getItem(btoa('CargosFilter')) ?? '') || '{}') : {} as FilterCargos;
            setWindowFilter(filtroMem);              
            handleFetchWithFilter(filtroMem); 




        
        setIsInitialized(true);
      }, [isInitialized, handleFetchWithFilter]); 

